@startuml
skinparam classAttributeIconSize 0
skinparam noteBackgroundColor #FFFFCC
skinparam noteBorderColor #000000
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor #000000
  ArrowColor #000000
}

class Context {
  + Strategy strategy
  + setStrategy(Strategy strategy)
  + execMethod()
}

interface Strategy {
  + method()
}

class StrategyImp1 {
  + method()
}

class StrategyImp2 {
  + method()
}

note as Note
public void execMethod() {
  strategy.method();
}
end note

Context --|> Note
Context o-- Strategy
Strategy <|-- StrategyImp1
Strategy <|-- StrategyImp2

note at bottom of diagram
策略模式
end note

@enduml
